/** Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val; this.left = left; this.right = right;
 *     }
 * }
 */
public class Codec {
    public String serialize(TreeNode root) {
        if (root == null) return "";
        StringBuilder sb = new StringBuilder();
        java.util.ArrayDeque<TreeNode> q = new java.util.ArrayDeque<>();
        q.offer(root);
        while (!q.isEmpty()) {
            TreeNode n = q.poll();
            if (n == null) { sb.append("null,"); continue; }
            sb.append(n.val).append(',');
            q.offer(n.left);
            q.offer(n.right);
        }
        return sb.toString();
    }
    public TreeNode deserialize(String data) {
        if (data == null || data.isEmpty()) return null;
        String[] parts = data.split(",");
        TreeNode root = new TreeNode(Integer.parseInt(parts[0]));
        java.util.ArrayDeque<TreeNode> q = new java.util.ArrayDeque<>();
        q.offer(root);
        int i = 1;
        while (!q.isEmpty() && i < parts.length) {
            TreeNode n = q.poll();
            if (i < parts.length && !parts[i].equals("null") && !parts[i].isEmpty()) {
                n.left = new TreeNode(Integer.parseInt(parts[i]));
                q.offer(n.left);
            }
            i++;
            if (i < parts.length && !parts[i].equals("null") && !parts[i].isEmpty()) {
                n.right = new TreeNode(Integer.parseInt(parts[i]));
                q.offer(n.right);
            }
            i++;
        }
        return root;
    }
}

