/** Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val; this.left = left; this.right = right;
 *     }
 * }
 */
class Solution {
    public java.util.List<java.util.List<Integer>> pathSum(TreeNode root, int targetSum) {
        java.util.List<java.util.List<Integer>> ans = new java.util.ArrayList<>();
        dfs(root, targetSum, new java.util.ArrayList<>(), ans);
        return ans;
    }
    private void dfs(TreeNode node, int remain, java.util.List<Integer> path,
                     java.util.List<java.util.List<Integer>> ans) {
        if (node == null) return;
        path.add(node.val);
        if (node.left == null && node.right == null && remain == node.val)
            ans.add(new java.util.ArrayList<>(path));
        else {
            dfs(node.left, remain - node.val, path, ans);
            dfs(node.right, remain - node.val, path, ans);
        }
        path.remove(path.size() - 1);
    }
}
